def _competitor_from_logits(candidate_logits: Mapping[str, Any], *, correct_key: str) -> str:
    best = None
    best_val = None
    for c in CHOICES:
        if c == correct_key:
            continue
        v = float(candidate_logits.get(c, float("-inf")))
        if (best is None) or (v > float(best_val)):
            best = c
            best_val = v
    return str(best) if best is not None else "A"
